#[no_mangle]
/// the rust entry-point of os
pub fn rust_main(hartid: usize) -> ! {
    if FIRST_HART.load(Ordering::SeqCst) {
        FIRST_HART.store(false, Ordering::SeqCst);
        clear_bss();
        println!("[kernel] Hello, world!");
        println!(
            r#"
                  ____                  
  _   _    __ _  |___ \   _   _    ___  
 | | | |  / _` |   __) | | | | |  / _ \ 
 | |_| | | (_| |  / __/  | |_| | | (_) |
  \__, |  \__,_| |_____|  \__, |  \___/ 
  |___/                   |___/         
            "#
        );
        #[cfg(target_arch = "loongarch64")]
        arch::memory_layout::print_memlayout();
        // 时钟频率初始化
        arch::time::init_clock_freq();
        // HXC: 我在这里加入了很多调试输出，因为是要提交给平台的，因此最好不要用debug!而是用print和println
        print!("mm::init...");
        mm::init();
        println!("complete.");

        print!("logger::init...");
        logger::init();
        println!("complete.");

        print!("trap::init...");
        trap::init();
        println!("complete.");

        print!("task::init...");
        task::init();
        println!("complete.");

        print!("fs::init...");
        fs::init();
        println!("complete.");

        print!("net::init...");
        #[cfg(all(feature = "net", target_arch = "loongarch64"))]
        let net_devices = DeviceContainer::default();
        #[cfg(all(feature = "net", target_arch = "riscv64"))]
        let net_devices = match NetDeviceImpl::try_new_device() {
            Some(device) => DeviceContainer::from_one(device),
            None => DeviceContainer::default(),
        };
        #[cfg(feature = "net")]
        net::init_network(net_devices);
        println!("complete.");

        print!("task::add_initproc...");
        task::add_initproc();
        println!("complete.");

        print!("START_HART_ID.store...");
        START_HART_ID.store(hartid, Ordering::SeqCst);
        println!("complete.");

        print!("INIT_FINISHED.store...");
        INIT_FINISHED.store(true, Ordering::SeqCst);
        println!("complete.");

        print!("trap::enable_timer_interrupt...");
        arch::trap_interface::enable_timer_interrupt();
        println!("complete.");

        print!("timer::set_next_trigger...");
        timer::set_next_trigger();
        println!("complete.");
    } else {
        // barrier
        while !INIT_FINISHED.load(Ordering::SeqCst) {
            core::hint::spin_loop();
        }

        println!(
            "[kernel] ---------- hart {} is starting... ----------",
            hartid
        );
        trap::init();
        mm::activate_kernel_space();
        arch::trap_interface::enable_timer_interrupt();
        timer::set_next_trigger();
    }
    if arch::cpu::hart_id() == START_HART_ID.load(Ordering::SeqCst) {
        fs::list_apps();
    }
    task::run_tasks();
    panic!("Unreachable in rust_main!");
}

