//! Fork / clone address space duplication.
//!
//! Contains `from_existed_user()` which creates a new [`MemorySetInner`] by
//! cloning an existing user address space with proper COW / shared-memory
//! semantics.

use super::super::group::GROUP_SHARE;
use super::super::map_area::MapType;
use super::super::memory_set::MemorySetInner;
use super::{MapArea, MapAreaType, MapPermission, VirtAddr, VirtPageNum};
use crate::arch::memory_layout::PAGE_SIZE;
use crate::arch::page_table::PageTable;
use crate::arch::tlb::tlb_invalidate;
use crate::mm::{page_fault_handler, MemorySet};
use crate::syscall::MmapFlags;
use alloc::sync::Arc;
use alloc::vec::Vec;

impl MemorySetInner {
    /// Clone a same `MemorySet`
    pub fn from_existed_user(user_space: &MemorySet) -> MemorySetInner {
        let mut memory_set = Self::new_from_kernel();

        // Pre-fault MAP_SHARED areas: lazy mmap pages need backing frames
        // allocated before forking, otherwise parent and child would each
        // independently allocate their own frames on page fault, breaking
        // MAP_SHARED semantics.
        {
            let u = user_space.get_mut();
            let areas_ptr: *mut Vec<MapArea> = &mut u.areas;
            let pt_ptr: *mut PageTable = &mut u.page_table;
            for area in unsafe { &mut *areas_ptr }.iter_mut() {
                if area.area_type != MapAreaType::Mmap
                    || !area.mmap_flags.contains(MmapFlags::MAP_SHARED)
                {
                    continue;
                }
                let pt = unsafe { &mut *pt_ptr };
                for vpn in area.vpn_range {
                    if !area.data_frames.contains_key(&vpn) {
                        if area.mmap_file.file.is_none() {
                            // MAP_ANONYMOUS: just allocate a zeroed frame
                            area.map_one(pt, vpn); // ignore OOM — lazy fault later
                        } else {
                            // file-backed: use the write-fault handler to
                            // read file data into the frame
                            let va = VirtAddr::from(vpn);
                            page_fault_handler::mmap_write_page_fault(va, pt, area);
                        }
                    }
                }
            }
        }

        for area in user_space.get_mut().areas.iter_mut() {
            // don't copy stack and trap
            if area.area_type == MapAreaType::Stack || area.area_type == MapAreaType::Trap {
                continue;
            }
            let mut new_area = MapArea::from_another(area);
            if area.area_type == MapAreaType::Mmap
                && area.mmap_flags.contains(MmapFlags::MAP_SHARED)
            {
                // 子进程继承 MAP_SHARED 的 groupid，增加引用计数后才允许
                // 父子在后续 lazy fault 中从 GROUP_SHARE 找到同一共享帧。
                GROUP_SHARE.lock().add_area(new_area.groupid);
            }
            // Mmap and brk are lazy allocation
            if area.area_type == MapAreaType::Mmap || area.area_type == MapAreaType::Brk {
                if area.mmap_flags.contains(MmapFlags::MAP_SHARED) {
                    let frames = area.data_frames.values().cloned().collect();
                    memory_set.push_with_given_frames(new_area, frames);
                    continue;
                }
                new_area.data_frames = area.data_frames.clone();
                // Iterate the full vpn_range for Brk areas: the parent may have
                // PTEs for VPNs not tracked in data_frames (e.g. after brk
                // shrink→grow cycles).  For each such VPN we must create a child
                // COW PTE so the child sees the parent's heap data instead of
                // a zero page from a subsequent lazy fault.
                let vpns: Vec<_> = if area.area_type == MapAreaType::Brk {
                    area.vpn_range.into_iter().collect()
                } else {
                    area.data_frames.keys().copied().collect()
                };
                for vpn in vpns {
                    if user_space.get_mut().page_table.translate(vpn).is_some() {
                        user_space
                            .get_mut()
                            .page_table
                            .handle_cow_mapping_from_exited_user(vpn, &mut memory_set);
                    }
                }
                memory_set.push_lazily(new_area);
                continue;
            }
            // ELF always COW
            if area.area_type == MapAreaType::Elf {
                for vpn in area.vpn_range {
                    user_space
                        .get_mut()
                        .page_table
                        .handle_cow_mapping_from_exited_user(vpn, &mut memory_set);
                }
                new_area.data_frames = area.data_frames.clone();
                memory_set.push_lazily(new_area);
                continue;
            }
            // Map the same frames for Shm
            if area.area_type == MapAreaType::Shm {
                let frames = area.data_frames.values().cloned().collect();
                memory_set.push_with_given_frames(new_area, frames);
                continue;
            }

            // neither COW nor mmap nor shm
            memory_set.push(new_area, None).ok();

            // copy data from another space
            for vpn in area.vpn_range {
                let src_ppn = user_space.translate(vpn).unwrap();
                let dst_ppn = memory_set.translate(vpn).unwrap();
                dst_ppn
                    .bytes_array_mut()
                    .copy_from_slice(src_ppn.bytes_array_mut());
            }
        }
        tlb_invalidate();
        memory_set
    }
}

//! 文件系统的环境上下文
use alloc::string::{String, ToString};
use hashbrown::HashMap;
use log::debug;
use spin::{RwLock, RwLockReadGuard, RwLockWriteGuard};

/// 文件相关信息
pub struct FSInfo {
    inner: RwLock<FSInfoInner>,
}

struct FSInfoInner {
    /// 当前工作路径
    cwd: String,
    /// 可执行文件绝对路径
    exe: String,
    /// 一个文件对应多个fd
    fd2path: HashMap<usize, String>,
    /// 文件模式创建掩码 (umask)，默认 0o022
    umask: u32,
}

impl FSInfoInner {
    // ----------基本方法----------
    /// 只有initproc会调用
    fn new_for_initproc() -> Self {
        let mut fd2path = HashMap::new();
        fd2path.insert(0, "stdin".to_string());
        fd2path.insert(1, "stdout".to_string());
        fd2path.insert(2, "stderr".to_string());
        Self {
            cwd: String::from("/"),
            fd2path,
            exe: String::from("/initproc"),
            umask: 0o022,
        }
    }
    fn from_another(another: &FSInfoInner) -> Self {
        Self {
            cwd: another.get_cwd(),
            exe: another.get_exe(),
            fd2path: another.fd2path.clone(),
            umask: another.umask,
        }
    }
    fn clear(&mut self) {
        self.cwd.clear();
        self.exe.clear();
        self.fd2path.clear();
    }
    // ----------cwd----------
    fn get_cwd(&self) -> String {
        self.cwd.clone()
    }

    fn set_cwd(&mut self, cwd: String) {
        // debug!("FSInfoInner::set_cwd: cwd is set to {}", cwd.as_str());
        self.cwd = cwd;
    }
    // ----------exe----------
    fn get_exe(&self) -> String {
        self.exe.clone()
    }

    fn set_exe(&mut self, exe: String) {
        self.exe = exe;
    }
    // ----------fd2path----------
    fn insert(&mut self, path: String, fd: usize) {
        self.fd2path.insert(fd, path);
    }
    fn has_fd(&self, path: &str) -> bool {
        self.fd2path.values().any(|v| v == path)
    }
    fn remove(&mut self, fd: usize) {
        self.fd2path.remove(&fd);
    }
}

impl FSInfo {
    /// 进程创建时调用
    pub fn new_initproc() -> Self {
        Self {
            inner: RwLock::new(FSInfoInner::new_for_initproc()),
        }
    }
    /// 通过已有对象进行创建
    pub fn from_another(another: &FSInfo) -> Self {
        let inner = another.inner.read();
        Self {
            inner: RwLock::new(FSInfoInner::from_another(&inner)),
        }
    }
    /// 清除自身
    pub fn clear(&self) {
        self.inner.write().clear();
    }
    /// 获取当前目录
    pub fn get_cwd(&self) -> String {
        self.inner.read().cwd.clone()
    }
    /// 修改当前目录
    pub fn set_cwd(&self, cwd: String) {
        // debug!("FSInfoInner::set_cwd: cwd is set to {}", cwd.as_str());
        self.inner.write().cwd = cwd;
    }
    /// 获取可执行文件的绝对路径
    pub fn get_exe(&self) -> String {
        self.inner.read().exe.clone()
    }
    /// 设置可执行文件的绝对路径
    pub fn set_exe(&self, exe: String) {
        self.inner.write().exe = exe;
    }
    /// 文件描述符表相关操作
    /// 插入文件描述相关映射
    pub fn insert(&self, path: String, fd: usize) {
        self.inner.write().fd2path.insert(fd, path);
    }
    /// 用于 dup 等操作：将源 fd 的路径复制给目标 fd
    pub fn dup_fd_path(&self, old_fd: usize, new_fd: usize) {
        let mut inner = self.inner.write();
        // 如果旧 fd 有路径记录，则拷贝给新 fd
        if let Some(path) = inner.fd2path.get(&old_fd).cloned() {
            inner.fd2path.insert(new_fd, path);
        }
    }
    /// 检查当前是否打开了某个特定路径的文件
    pub fn has_fd(&self, path: &str) -> bool {
        self.inner.read().fd2path.values().any(|v| v == path)
    }
    /// 关闭文件时移除映射
    pub fn remove(&self, fd: usize) {
        self.inner.write().fd2path.remove(&fd);
    }
    /// 获取当前的 umask 值
    pub fn get_umask(&self) -> u32 {
        self.inner.read().umask
    }
    /// 设置新的 umask 值（仅低 9 位有效），返回旧的 umask
    pub fn set_umask(&self, mask: u32) -> u32 {
        let mut inner = self.inner.write();
        let old = inner.umask;
        inner.umask = mask & 0o777;
        old
    }
}

