/// 全局单例挂载表
///
/// - `Lazy`: 确保在第一次使用时才初始化内存。
/// - `Arc`: 原子引用计数，允许跨线程共享该实例。
/// - `Mutex`: 互斥锁，确保在多核并发操作挂载表时不会出现竞态条件。
pub static MNT_TABLE: Lazy<Arc<Mutex<MountTable>>> = Lazy::new(|| {
    let mnt_table = MountTable {
